customCss:
@import url('https://fonts.googleapis.com/css2?family=Righteous&family=Quicksand:wght@400;500;600;700&display=swap');
:root { --font-body: 'Quicksand', sans-serif; --font-display: 'Righteous', cursive; --radius: 16px; --ambient-glow-opacity: 0.2; }

/* ── Retro grid floor under hero ── */
.home-hero::after { content: ''; position: absolute; bottom: 0; left: 0; right: 0; height: 40%; background: linear-gradient(transparent 0%, rgba(255,113,206,0.05) 100%), repeating-linear-gradient(90deg, rgba(1,205,254,0.06) 0px, transparent 1px, transparent 60px), repeating-linear-gradient(0deg, rgba(1,205,254,0.06) 0px, transparent 1px, transparent 60px); pointer-events: none; z-index: 4; mask-image: linear-gradient(transparent, black); -webkit-mask-image: linear-gradient(transparent, black); }

/* ── Cards: soft glow, extra round, gradient border ── */
.media-card-image { border-radius: 14px; border: 1px solid rgba(255,113,206,0.2); overflow: hidden; }
.media-card:hover .media-card-image { box-shadow: 0 8px 30px rgba(255,113,206,0.25), 0 4px 15px rgba(1,205,254,0.15); border-color: rgba(255,113,206,0.5); }
.media-card:hover { transform: translateY(-6px) scale(1.02); }

/* ── Section headers: display font, gradient text ── */
.section-header { font-family: 'Righteous', cursive; font-size: 1.1rem; letter-spacing: 0.04em; background: linear-gradient(135deg, #ff71ce, #01cdfe); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }

/* ── Page titles: big retro display ── */
.page-title { font-family: 'Righteous', cursive; }

/* ── Sidebar: dreamy blur ── */
aside { backdrop-filter: blur(20px) saturate(1.4); border-right: 1px solid rgba(255,113,206,0.15) !important; }
.sidebar-logo-icon { border-radius: 12px; background: linear-gradient(135deg, rgba(255,113,206,0.2), rgba(1,205,254,0.2)); }

/* ── Badges: pastel pills ── */
.metadata-badge { border-radius: 9999px; background: linear-gradient(135deg, rgba(255,113,206,0.12), rgba(1,205,254,0.12)); border: 1px solid rgba(255,113,206,0.2); }

/* ── Pill buttons: gradient ── */
.pill-primary { background: linear-gradient(135deg, #ff71ce, #b967ff) !important; border: none; box-shadow: 0 4px 16px rgba(255,113,206,0.3); }
.pill-primary:hover { box-shadow: 0 6px 24px rgba(255,113,206,0.5); transform: translateY(-1px); }

/* ── Glass effects: purple tinted ── */
.glass, .glass-subtle, .glass-dark { border: 1px solid rgba(185,103,255,0.15); }

/* ── Surface panels: extra soft ── */
.surface-panel { border-radius: 18px; border: 1px solid rgba(185,103,255,0.1); }

/* ── Tab bar: rounded pills ── */
.tab-active { border-radius: 9999px; background: linear-gradient(135deg, rgba(255,113,206,0.15), rgba(1,205,254,0.15)); }

/* ── Hero backdrop: oversaturated dream ── */
:root { --hero-backdrop-brightness: 0.65; --hero-backdrop-saturate: 1.6; }

/* ── Progress bars: gradient ── */
.progress-fill { background: linear-gradient(90deg, #ff71ce, #01cdfe) !important; }
